import React, { useEffect, useState } from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import Spinner from "../components/shared/Spinner";
import Layout from "../components/shared/Layout/Layout";
import Modal from "../components/shared/modal/Modal";
import API from "../services/API";
import moment from "moment";

const facts = [
  {
    icon: "💉",
    text: "1 donation can save up to 3 lives — your blood is separated into red cells, plasma & platelets.",
  },
  {
    icon: "⏱️",
    text: "The whole donation process takes only 8–10 minutes. You're a hero in under 15!",
  },
  {
    icon: "🔁",
    text: "Your body fully replenishes donated blood within 24–48 hours.",
  },
  {
    icon: "🩺",
    text: "Before donating, you get a free mini health checkup — blood pressure, haemoglobin & more.",
  },
  {
    icon: "🔒",
    text: "Your identity is 100% private. Hospitals only see blood type — never your name or contact.",
  },
  {
    icon: "🌍",
    text: "Every 2 seconds, someone in the world needs blood. Your one donation matters enormously.",
  },
];

const bloodGroups = ["O+", "O-", "A+", "A-", "B+", "B-", "AB+", "AB-"];

const HomePage = () => {
  const { loading, error, user } = useSelector((state) => state.auth);
  const [data, setData] = useState([]);
  const [totalOrgs, setTotalOrgs] = useState(0);
  const [camps, setCamps] = useState([]);
  const [orgs, setOrgs] = useState([]);
  const [factIndex, setFactIndex] = useState(0);
  const [showRequest, setShowRequest] = useState(false);
  const [reqBloodGroup, setReqBloodGroup] = useState("");
  const [reqQuantity, setReqQuantity] = useState("");
  const [reqOrgEmail, setReqOrgEmail] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const navigate = useNavigate();

  const isOrg = user?.role === "organisation";
  const isDonor = user?.role === "donar";
  const isHospital = user?.role === "hospital";

  const getOrgRecords = async () => {
    try {
      const { data } = await API.get("/inventory/get-inventory");
      if (data?.success) setData(data?.inventory);
    } catch (error) {
      console.log(error);
    }
  };

  const getDonorRecords = async () => {
    try {
      const { data } = await API.post("/inventory/get-inventory-hospital", {
        filters: { inventoryType: "in", donar: user?._id },
      });
      if (data?.success) setData(data?.inventory);
    } catch (error) {
      console.log(error);
    }
  };

  const getHospitalRecords = async () => {
    try {
      const { data } = await API.post("/inventory/get-inventory-hospital", {
        filters: { inventoryType: "out", hospital: user?._id },
      });
      if (data?.success) setData(data?.inventory);
    } catch (error) {
      console.log(error);
    }
  };

  const getTotalOrgs = async () => {
    try {
      const { data } = await API.get("/inventory/get-all-organisations");
      if (data?.success) {
        setTotalOrgs(data?.organisations?.length || 0);
        setOrgs(data?.organisations || []);
      }
    } catch (error) {
      console.log(error);
    }
  };

  const getCamps = async () => {
    try {
      const { data } = await API.get("/camp/get-all-camps");
      if (data?.success) setCamps(data?.camps);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    if (isOrg) getOrgRecords();
    else if (isDonor) getDonorRecords();
    else if (isHospital) getHospitalRecords();
    getTotalOrgs();
    getCamps();
    const interval = setInterval(
      () => setFactIndex((i) => (i + 1) % facts.length),
      4000,
    );
    return () => clearInterval(interval);
  }, [user]);

  const handleBloodRequest = async () => {
    try {
      if (!reqBloodGroup || !reqQuantity || !reqOrgEmail)
        return alert("Please fill all fields");
      setSubmitting(true);
      const { data } = await API.post("/inventory/create-inventory", {
        email: reqOrgEmail,
        organisation: orgs.find((o) => o.email === reqOrgEmail)?._id,
        inventoryType: "out",
        bloodGroup: reqBloodGroup,
        quantity: Number(reqQuantity),
      });
      if (data?.success) {
        alert("Blood request submitted successfully! ✅");
        setShowRequest(false);
        setReqBloodGroup("");
        setReqQuantity("");
        setReqOrgEmail("");
        getHospitalRecords();
      }
    } catch (error) {
      alert(error?.response?.data?.message || "Something went wrong");
    } finally {
      setSubmitting(false);
    }
  };

  // Blood group summary for hospital
  const bloodSummary = bloodGroups
    .map((bg) => ({
      group: bg,
      total: data
        .filter((r) => r.bloodGroup === bg)
        .reduce((sum, r) => sum + (Number(r.quantity) || 0), 0),
    }))
    .filter((b) => b.total > 0);

  return (
    <Layout>
      {user?.role === "admin" && navigate("/admin")}
      {error && <span>{alert(error)}</span>}
      {loading ? (
        <Spinner />
      ) : (
        <>
          <style>{`
            @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
            .hemo-home { font-family: 'DM Sans', sans-serif; }
            .hemo-greeting { margin-bottom: 28px; }
            .hemo-greeting-hi { font-family: 'Syne', sans-serif; font-size: 28px; font-weight: 700; color: #fff; margin-bottom: 4px; }
            .hemo-greeting-sub { font-size: 15px; color: rgba(255,255,255,0.4); }
            .hemo-greeting-name { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
            .hemo-stats { display: flex; gap: 16px; margin-bottom: 28px; flex-wrap: wrap; }
            .hemo-stat-card { flex: 1; min-width: 160px; padding: 20px 22px; border-radius: 18px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); backdrop-filter: blur(12px); transition: transform 0.2s, border-color 0.2s; }
            .hemo-stat-card:hover { transform: translateY(-3px); border-color: rgba(168,85,247,0.3); }
            .hemo-stat-icon { font-size: 26px; margin-bottom: 10px; }
            .hemo-stat-num { font-family: 'Syne', sans-serif; font-size: 30px; font-weight: 800; color: #fff; margin-bottom: 2px; }
            .hemo-stat-num span { font-size: 16px; color: rgba(255,255,255,0.3); }
            .hemo-stat-label { font-size: 13px; color: rgba(255,255,255,0.4); }
            .hemo-stat-card.purple { border-color: rgba(168,85,247,0.25); background: rgba(168,85,247,0.08); }
            .hemo-stat-card.pink { border-color: rgba(236,72,153,0.25); background: rgba(236,72,153,0.08); }
            .hemo-stat-card.blue { border-color: rgba(99,102,241,0.25); background: rgba(99,102,241,0.08); }
            .hemo-stat-card.green { border-color: rgba(34,197,94,0.25); background: rgba(34,197,94,0.08); }
            .hemo-fact-card { padding: 18px 22px; border-radius: 16px; margin-bottom: 28px; background: linear-gradient(135deg, rgba(168,85,247,0.12), rgba(236,72,153,0.08)); border: 1px solid rgba(168,85,247,0.2); display: flex; align-items: center; gap: 14px; }
            .hemo-fact-icon { font-size: 24px; flex-shrink: 0; }
            .hemo-fact-text { font-size: 14px; color: rgba(255,255,255,0.75); line-height: 1.5; }
            .hemo-fact-label { font-size: 10px; font-weight: 600; text-transform: uppercase; letter-spacing: 1px; color: #a855f7; margin-bottom: 4px; }
            .hemo-two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 28px; }
            @media (max-width: 900px) { .hemo-two-col { grid-template-columns: 1fr; } }
            .hemo-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 18px; padding: 22px; backdrop-filter: blur(12px); }
            .hemo-card-title { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; color: rgba(255,255,255,0.85); margin-bottom: 16px; display: flex; align-items: center; gap: 8px; }
            .hemo-add-btn { display: inline-flex; align-items: center; gap: 8px; padding: 10px 20px; border-radius: 12px; border: none; cursor: pointer; background: linear-gradient(135deg, #9333ea, #ec4899); color: white; font-size: 14px; font-weight: 600; font-family: 'DM Sans', sans-serif; box-shadow: 0 4px 16px rgba(147,51,234,0.35); transition: all 0.2s; margin-bottom: 18px; }
            .hemo-add-btn:hover { transform: translateY(-2px); }
            .hemo-table { width: 100%; border-collapse: collapse; font-size: 13px; }
            .hemo-table th { text-align: left; padding: 10px 12px; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; border-bottom: 1px solid rgba(255,255,255,0.06); }
            .hemo-table td { padding: 12px 12px; color: rgba(255,255,255,0.7); border-bottom: 1px solid rgba(255,255,255,0.04); }
            .hemo-table tr:hover td { background: rgba(168,85,247,0.05); }
            .hemo-badge { display: inline-block; padding: 3px 10px; border-radius: 8px; font-size: 11px; font-weight: 600; }
            .hemo-badge-in { background: rgba(34,197,94,0.15); color: #4ade80; }
            .hemo-badge-out { background: rgba(239,68,68,0.15); color: #f87171; }
            .hemo-badge-blood { background: rgba(168,85,247,0.15); color: #c084fc; }
            .hemo-empty { text-align: center; padding: 40px; color: rgba(255,255,255,0.2); font-size: 14px; }
            .hemo-steps { display: flex; flex-direction: column; gap: 12px; }
            .hemo-step { display: flex; align-items: flex-start; gap: 12px; }
            .hemo-step-num { width: 28px; height: 28px; border-radius: 8px; flex-shrink: 0; background: linear-gradient(135deg, #9333ea, #ec4899); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 700; color: white; }
            .hemo-step-text { font-size: 13px; color: rgba(255,255,255,0.6); line-height: 1.5; padding-top: 4px; }
            .hemo-step-text strong { color: rgba(255,255,255,0.85); }
            .hemo-camp-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 14px; padding: 16px; margin-bottom: 10px; display: flex; align-items: flex-start; gap: 14px; transition: border-color 0.2s; }
            .hemo-camp-card:hover { border-color: rgba(168,85,247,0.3); }
            .hemo-camp-icon { font-size: 22px; flex-shrink: 0; margin-top: 2px; }
            .hemo-camp-name { font-size: 14px; font-weight: 600; color: rgba(255,255,255,0.85); margin-bottom: 4px; }
            .hemo-camp-addr { font-size: 12px; color: rgba(255,255,255,0.4); margin-bottom: 3px; }
            .hemo-camp-date { font-size: 11px; color: #a855f7; font-weight: 500; }
            .hemo-camp-org { font-size: 11px; color: rgba(34,197,94,0.8); margin-top: 4px; }
            .hemo-camp-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.15); color: #4ade80; margin-left: 8px; }
            .hemo-no-camps { text-align: center; padding: 30px; color: rgba(255,255,255,0.2); font-size: 13px; }
            .hemo-donate-link { display: inline-block; margin-top: 14px; padding: 10px 20px; border-radius: 12px; background: linear-gradient(135deg, #9333ea, #ec4899); color: white; font-size: 13px; font-weight: 600; text-decoration: none; font-family: 'DM Sans', sans-serif; }
            /* Hospital request form */
            .req-form { background: rgba(168,85,247,0.07); border: 1px solid rgba(168,85,247,0.2); border-radius: 20px; padding: 24px; margin-bottom: 28px; animation: slideDown 0.3s ease; }
            @keyframes slideDown { from { opacity:0; transform:translateY(-10px); } to { opacity:1; transform:translateY(0); } }
            .req-form-title { font-family: 'Syne', sans-serif; font-size: 16px; font-weight: 700; color: #fff; margin-bottom: 16px; }
            .req-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 14px; margin-bottom: 16px; }
            @media(max-width:700px){ .req-grid { grid-template-columns: 1fr; } }
            .req-field label { display: block; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.4); text-transform: uppercase; letter-spacing: 0.8px; margin-bottom: 8px; }
            .req-field select, .req-field input { width: 100%; padding: 11px 13px; border-radius: 12px; background: rgba(255,255,255,0.06); border: 1.5px solid rgba(255,255,255,0.1); color: #fff; font-size: 14px; font-family: 'DM Sans', sans-serif; outline: none; transition: all 0.2s; }
            .req-field select option { background: #1a0030; color: #fff; }
            .req-field select:focus, .req-field input:focus { border-color: #a855f7; background: rgba(168,85,247,0.1); }
            .req-field input::placeholder { color: rgba(255,255,255,0.2); }
            .req-actions { display: flex; gap: 12px; }
            .req-submit { padding: 11px 26px; border-radius: 12px; border: none; cursor: pointer; background: linear-gradient(135deg, #9333ea, #ec4899); color: white; font-size: 14px; font-weight: 600; font-family: 'DM Sans', sans-serif; transition: all 0.2s; }
            .req-submit:disabled { opacity: 0.6; cursor: not-allowed; }
            .req-cancel { padding: 11px 20px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: transparent; color: rgba(255,255,255,0.5); font-size: 14px; cursor: pointer; font-family: 'DM Sans', sans-serif; }
            /* Blood group grid */
            .blood-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; }
            @media(max-width:600px){ .blood-grid { grid-template-columns: repeat(2,1fr); } }
            .blood-pill { padding: 14px 10px; border-radius: 14px; text-align: center; background: rgba(168,85,247,0.08); border: 1px solid rgba(168,85,247,0.2); }
            .blood-pill-group { font-family: 'Syne', sans-serif; font-size: 18px; font-weight: 800; color: #c084fc; }
            .blood-pill-qty { font-size: 12px; color: rgba(255,255,255,0.4); margin-top: 4px; }
            .blood-pill-empty { padding: 14px 10px; border-radius: 14px; text-align: center; background: rgba(255,255,255,0.02); border: 1px solid rgba(255,255,255,0.05); }
            .blood-pill-empty-group { font-family: 'Syne', sans-serif; font-size: 18px; font-weight: 800; color: rgba(255,255,255,0.15); }
            .blood-pill-empty-qty { font-size: 11px; color: rgba(255,255,255,0.15); margin-top: 4px; }
          `}</style>

          <div className="hemo-home">
            <div className="hemo-greeting">
              <div className="hemo-greeting-hi">
                Hey,{" "}
                <span className="hemo-greeting-name">
                  {user?.name ||
                    user?.organisationName ||
                    user?.hospitalName ||
                    "there"}
                </span>{" "}
                👋
              </div>
              <div className="hemo-greeting-sub">
                {isOrg && "Manage your blood inventory below"}
                {isDonor && "Welcome to HemoLink — every drop counts 🩸"}
                {isHospital && "Manage your blood requests and supply below 🏥"}
              </div>
            </div>

            {/* HOSPITAL SPECIFIC HOME */}
            {isHospital && (
              <>
                <div className="hemo-stats">
                  <div className="hemo-stat-card purple">
                    <div className="hemo-stat-icon">🩸</div>
                    <div className="hemo-stat-num">{data.length}</div>
                    <div className="hemo-stat-label">Total Blood Requests</div>
                  </div>
                  <div className="hemo-stat-card pink">
                    <div className="hemo-stat-icon">💧</div>
                    <div className="hemo-stat-num">
                      {data.reduce(
                        (sum, r) => sum + (Number(r.quantity) || 0),
                        0,
                      )}
                    </div>
                    <div className="hemo-stat-label">Total ML Received</div>
                  </div>
                  <div className="hemo-stat-card blue">
                    <div className="hemo-stat-icon">🏢</div>
                    <div className="hemo-stat-num">{totalOrgs}</div>
                    <div className="hemo-stat-label">Blood Banks Available</div>
                  </div>
                  <div className="hemo-stat-card green">
                    <div className="hemo-stat-icon">🏕️</div>
                    <div className="hemo-stat-num">{camps.length}</div>
                    <div className="hemo-stat-label">Active Donation Camps</div>
                  </div>
                </div>

                <button
                  className="hemo-add-btn"
                  onClick={() => setShowRequest(!showRequest)}
                >
                  {showRequest ? "✕ Cancel" : "🩸 Request Blood"}
                </button>

                {showRequest && (
                  <div className="req-form">
                    <div className="req-form-title">
                      📋 Request Blood from Organisation
                    </div>
                    <div className="req-grid">
                      <div className="req-field">
                        <label>Blood Group</label>
                        <select
                          value={reqBloodGroup}
                          onChange={(e) => setReqBloodGroup(e.target.value)}
                        >
                          <option value="">Select blood group</option>
                          {bloodGroups.map((bg) => (
                            <option key={bg} value={bg}>
                              {bg}
                            </option>
                          ))}
                        </select>
                      </div>
                      <div className="req-field">
                        <label>Quantity (ML)</label>
                        <input
                          type="number"
                          placeholder="e.g. 500"
                          value={reqQuantity}
                          onChange={(e) => setReqQuantity(e.target.value)}
                        />
                      </div>
                      <div className="req-field">
                        <label>Organisation</label>
                        <select
                          value={reqOrgEmail}
                          onChange={(e) => setReqOrgEmail(e.target.value)}
                        >
                          <option value="">Select blood bank</option>
                          {orgs.map((org) => (
                            <option key={org._id} value={org.email}>
                              {org.organisationName}
                            </option>
                          ))}
                        </select>
                      </div>
                    </div>
                    <div className="req-actions">
                      <button
                        className="req-submit"
                        onClick={handleBloodRequest}
                        disabled={submitting}
                      >
                        {submitting ? "Submitting..." : "Submit Request →"}
                      </button>
                      <button
                        className="req-cancel"
                        onClick={() => setShowRequest(false)}
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                )}

                <div className="hemo-two-col">
                  <div className="hemo-card">
                    <div className="hemo-card-title">
                      🩸 Recent Blood Requests
                    </div>
                    {data.length === 0 ? (
                      <div className="hemo-empty">
                        No requests yet — click "Request Blood" above
                      </div>
                    ) : (
                      <table className="hemo-table">
                        <thead>
                          <tr>
                            <th>Blood</th>
                            <th>Qty</th>
                            <th>From</th>
                            <th>Date</th>
                          </tr>
                        </thead>
                        <tbody>
                          {data.slice(0, 6).map((record) => (
                            <tr key={record._id}>
                              <td>
                                <span className="hemo-badge hemo-badge-blood">
                                  {record.bloodGroup}
                                </span>
                              </td>
                              <td>{record.quantity} ml</td>
                              <td>
                                {record.organisation?.organisationName || "—"}
                              </td>
                              <td>
                                {moment(record.createdAt).format("DD MMM YY")}
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    )}
                  </div>

                  <div className="hemo-card">
                    <div className="hemo-card-title">
                      💉 Blood Groups Received
                    </div>
                    {bloodSummary.length === 0 ? (
                      <div className="hemo-empty">No blood received yet</div>
                    ) : (
                      <div className="blood-grid">
                        {bloodGroups.map((bg) => {
                          const found = bloodSummary.find(
                            (b) => b.group === bg,
                          );
                          return found ? (
                            <div className="blood-pill" key={bg}>
                              <div className="blood-pill-group">{bg}</div>
                              <div className="blood-pill-qty">
                                {found.total} ml
                              </div>
                            </div>
                          ) : (
                            <div className="blood-pill-empty" key={bg}>
                              <div className="blood-pill-empty-group">{bg}</div>
                              <div className="blood-pill-empty-qty">0 ml</div>
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                </div>

                <div className="hemo-card" style={{ marginBottom: 28 }}>
                  <div className="hemo-card-title">
                    📍 Active Blood Donation Camps
                  </div>
                  <p
                    style={{
                      fontSize: 13,
                      color: "rgba(255,255,255,0.35)",
                      marginBottom: 16,
                    }}
                  >
                    More camps = more blood supply coming in — share these with
                    your community!
                  </p>
                  {camps.length === 0 ? (
                    <div className="hemo-no-camps">
                      No active camps right now.
                    </div>
                  ) : (
                    camps.map((camp) => (
                      <div className="hemo-camp-card" key={camp._id}>
                        <div className="hemo-camp-icon">🏕️</div>
                        <div>
                          <div className="hemo-camp-name">
                            {camp.campName}{" "}
                            <span className="hemo-camp-badge">Active</span>
                          </div>
                          <div className="hemo-camp-addr">
                            📍 {camp.address}
                          </div>
                          <div className="hemo-camp-date">
                            📅 {moment(camp.date).format("DD MMM YYYY")} &nbsp;
                            🕐 {camp.time}
                          </div>
                          <div className="hemo-camp-org">
                            ✅ By: {camp.organisation?.organisationName}
                          </div>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </>
            )}

            {/* DONOR HOME */}
            {isDonor && (
              <>
                <div className="hemo-stats">
                  <div className="hemo-stat-card purple">
                    <div className="hemo-stat-icon">🩸</div>
                    <div className="hemo-stat-num">
                      {data.length}
                      <span>+</span>
                    </div>
                    <div className="hemo-stat-label">Your Donations</div>
                  </div>
                  <div className="hemo-stat-card pink">
                    <div className="hemo-stat-icon">🏢</div>
                    <div className="hemo-stat-num">{totalOrgs}</div>
                    <div className="hemo-stat-label">
                      Organisations on HemoLink
                    </div>
                  </div>
                  <div className="hemo-stat-card blue">
                    <div className="hemo-stat-icon">🏕️</div>
                    <div className="hemo-stat-num">{camps.length}</div>
                    <div className="hemo-stat-label">Active Donation Camps</div>
                  </div>
                </div>

                <div className="hemo-fact-card">
                  <div className="hemo-fact-icon">{facts[factIndex].icon}</div>
                  <div>
                    <div className="hemo-fact-label">Did you know?</div>
                    <div className="hemo-fact-text">
                      {facts[factIndex].text}
                    </div>
                  </div>
                </div>

                <div className="hemo-two-col">
                  <div className="hemo-card">
                    <div className="hemo-card-title">
                      🗃️ Your Recent Donations
                    </div>
                    {data.length === 0 ? (
                      <div className="hemo-empty">
                        <div style={{ fontSize: 36, marginBottom: 8 }}>🩸</div>
                        <div>No donations yet!</div>
                        <a href="/donation" className="hemo-donate-link">
                          Record Your First Donation →
                        </a>
                      </div>
                    ) : (
                      <table className="hemo-table">
                        <thead>
                          <tr>
                            <th>Blood</th>
                            <th>Type</th>
                            <th>Qty</th>
                            <th>Date</th>
                          </tr>
                        </thead>
                        <tbody>
                          {data.slice(0, 6).map((record) => (
                            <tr key={record._id}>
                              <td>
                                <span className="hemo-badge hemo-badge-blood">
                                  {record.bloodGroup}
                                </span>
                              </td>
                              <td>
                                <span className="hemo-badge hemo-badge-in">
                                  Donated
                                </span>
                              </td>
                              <td>{record.quantity} ml</td>
                              <td>
                                {moment(record.createdAt).format("DD MMM YY")}
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    )}
                  </div>
                  <div className="hemo-card">
                    <div className="hemo-card-title">
                      🩸 How to Donate Blood
                    </div>
                    <div className="hemo-steps">
                      {[
                        [
                          "Register",
                          "Create your HemoLink donor account (done! ✅)",
                        ],
                        [
                          "Find a Camp",
                          "Check active camps below or on the Organisations page",
                        ],
                        [
                          "Visit & Donate",
                          "Walk in — the whole process takes 10–15 mins",
                        ],
                        [
                          "Record It",
                          "Log your donation under My Donations page",
                        ],
                        [
                          "Rest & Hydrate",
                          "Drink water, have a snack. You're a hero! 🎉",
                        ],
                      ].map(([title, desc], i) => (
                        <div className="hemo-step" key={i}>
                          <div className="hemo-step-num">{i + 1}</div>
                          <div className="hemo-step-text">
                            <strong>{title}:</strong> {desc}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <div className="hemo-card" style={{ marginBottom: 28 }}>
                  <div className="hemo-card-title">
                    📍 Active Blood Donation Camps Near You
                  </div>
                  <p
                    style={{
                      fontSize: 13,
                      color: "rgba(255,255,255,0.35)",
                      marginBottom: 16,
                    }}
                  >
                    Real camps by verified blood banks on HemoLink.
                  </p>
                  {camps.length === 0 ? (
                    <div className="hemo-no-camps">
                      No active camps right now. Check back soon!
                    </div>
                  ) : (
                    camps.map((camp) => (
                      <div className="hemo-camp-card" key={camp._id}>
                        <div className="hemo-camp-icon">🏕️</div>
                        <div>
                          <div className="hemo-camp-name">
                            {camp.campName}{" "}
                            <span className="hemo-camp-badge">Active</span>
                          </div>
                          <div className="hemo-camp-addr">
                            📍 {camp.address}
                          </div>
                          <div className="hemo-camp-date">
                            📅 {moment(camp.date).format("DD MMM YYYY")} &nbsp;
                            🕐 {camp.time}
                          </div>
                          <div className="hemo-camp-org">
                            ✅ Organised by:{" "}
                            {camp.organisation?.organisationName}
                          </div>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </>
            )}

            {/* ORG HOME */}
            {isOrg && (
              <>
                <div className="hemo-stats">
                  <div className="hemo-stat-card purple">
                    <div className="hemo-stat-icon">🩸</div>
                    <div className="hemo-stat-num">{data.length}</div>
                    <div className="hemo-stat-label">Blood Records</div>
                  </div>
                  <div className="hemo-stat-card pink">
                    <div className="hemo-stat-icon">📥</div>
                    <div className="hemo-stat-num">
                      {data.filter((r) => r.inventoryType === "in").length}
                    </div>
                    <div className="hemo-stat-label">Donations Received</div>
                  </div>
                  <div className="hemo-stat-card blue">
                    <div className="hemo-stat-icon">📤</div>
                    <div className="hemo-stat-num">
                      {data.filter((r) => r.inventoryType === "out").length}
                    </div>
                    <div className="hemo-stat-label">Sent to Hospitals</div>
                  </div>
                </div>

                <button
                  className="hemo-add-btn"
                  data-bs-toggle="modal"
                  data-bs-target="#staticBackdrop"
                >
                  + Add Inventory
                </button>

                <div className="hemo-card" style={{ marginBottom: 28 }}>
                  <div className="hemo-card-title">🗃️ Blood Inventory</div>
                  {data.length === 0 ? (
                    <div className="hemo-empty">
                      No records yet — add inventory above
                    </div>
                  ) : (
                    <table className="hemo-table">
                      <thead>
                        <tr>
                          <th>Blood</th>
                          <th>Type</th>
                          <th>Qty</th>
                          <th>Date</th>
                        </tr>
                      </thead>
                      <tbody>
                        {data.slice(0, 8).map((record) => (
                          <tr key={record._id}>
                            <td>
                              <span className="hemo-badge hemo-badge-blood">
                                {record.bloodGroup}
                              </span>
                            </td>
                            <td>
                              <span
                                className={`hemo-badge ${record.inventoryType === "in" ? "hemo-badge-in" : "hemo-badge-out"}`}
                              >
                                {record.inventoryType === "in" ? "In" : "Out"}
                              </span>
                            </td>
                            <td>{record.quantity} ml</td>
                            <td>
                              {moment(record.createdAt).format("DD MMM YY")}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
                </div>
              </>
            )}
          </div>
          <Modal />
        </>
      )}
    </Layout>
  );
};

export default HomePage;
